import React, { useEffect, useState } from "react";
import { useParams, useNavigate } from "react-router-dom";
import axios from "axios";
import "../index.css";

const Checkout = () => {
  const { id } = useParams();
  const navigate = useNavigate();
  const [product, setProduct] = useState(null);
  const [formData, setFormData] = useState({
    date: "",
    category: "",
    modeOfPayment: "",
    issue: "",
  });
  const [orderPlaced, setOrderPlaced] = useState(false);

  useEffect(() => {
    axios
      .get(`http://localhost:5000/api/products/${id}`)
      .then((res) => setProduct(res.data))
      .catch((err) => console.error("Error loading product:", err));
  }, [id]);

  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const handleSubmit = (e) => {
    e.preventDefault();

    // Later you can save to backend or localStorage
    console.log("Order data:", { ...formData, product });

    setOrderPlaced(true);

    setTimeout(() => {
      navigate("/orders");
    }, 2000);
  };

  if (!product) return <p>Loading product...</p>;

  if (orderPlaced)
    return <h2 className="success-msg">✅ Order placed successfully!</h2>;

  return (
    <div className="checkout-container">
      <h2>Checkout</h2>
      <div className="checkout-details">
        <p><strong>Product:</strong> {product.name}</p>
        <p><strong>Price:</strong> ₹{product.price}</p>
      </div>

      <form onSubmit={handleSubmit} className="checkout-form">
        <label>Date of Purchase:</label>
        <input
          type="date"
          name="date"
          value={formData.date}
          onChange={handleChange}
          required
        />

        <label>Category:</label>
        <input
          type="text"
          name="category"
          value={formData.category}
          onChange={handleChange}
          placeholder="e.g. Electronics"
          required
        />

        <label>Mode of Payment:</label>
        <select
          name="modeOfPayment"
          value={formData.modeOfPayment}
          onChange={handleChange}
          required
        >
          <option value="">Select</option>
          <option value="UPI">UPI</option>
          <option value="Credit Card">Credit Card</option>
          <option value="Debit Card">Debit Card</option>
          <option value="Cash on Delivery">Cash on Delivery</option>
        </select>

        <label>Any Issue or Note:</label>
        <textarea
          name="issue"
          value={formData.issue}
          onChange={handleChange}
          placeholder="Mention if any problem..."
        />

        <button type="submit" className="place-order-btn">Place Order</button>
      </form>
    </div>
  );
};

export default Checkout;
